console.log("Data models defined (JSDoc).");

/**
 * @typedef {import('../data_models').OHLCVData} OHLCVData
 * @typedef {import('../data_models').IndicatorPoint} IndicatorPoint
 * @typedef {import('../data_models').IndicatorOutput} IndicatorOutput
 */

/**
 * Calculates the Accumulation/Distribution Line (A/D Line).
 * 1. Money Flow Multiplier (MFM) = [(Close - Low) - (High - Close)] / (High - Low)
 *    If High == Low, MFM = 0.
 * 2. Money Flow Volume (MFV) = MFM * Volume
 * 3. A/D Line = Previous A/D Line + Current MFV
 *    The first A/D value is the MFV of the first period.
 *
 * @param {OHLCVData} data - Array of OHLCV data points. Requires 'high', 'low', 'close', 'volume'.
 * @returns {IndicatorOutput} Array of A/D Line values. The length is equal to the input data length.
 */
function calculateADLine(data) {
  if (!data || data.length === 0) {
    return [];
  }

  const adLineValues = [];
  let cumulativeADL = 0;

  for (let i = 0; i < data.length; i++) {
    const point = data[i];
    const { high, low, close, volume } = point;

    let mfm = 0; // Money Flow Multiplier
    const range = high - low;

    if (range !== 0) {
      mfm = ((close - low) - (high - close)) / range;
    } 
    // If range is 0, MFM remains 0. This handles cases where H=L (and thus C must be H and L).
    // Some definitions might use previous MFM or other rules if H=L=C, but MFM=0 is common.

    const mfv = mfm * volume; // Money Flow Volume

    if (i === 0) {
      cumulativeADL = mfv; // First A/D value is the MFV of the first period
    } else {
      cumulativeADL += mfv;
    }

    adLineValues.push({
      timestamp: point.timestamp,
      value: cumulativeADL,
    });
  }

  return adLineValues;
}

module.exports = { calculateADLine };

console.log("Accumulation/Distribution Line function defined in financial-indicators/lib/indicators/ad_line.js");

/**
 * @typedef {import('../data_models').OHLCVData} OHLCVData
 * @typedef {import('../data_models').OHLCVDataPoint} OHLCVDataPoint
 * @typedef {import('../data_models').IndicatorPoint} IndicatorPoint
 * @typedef {import('../data_models').IndicatorOutput} IndicatorOutput
 */

const { wildersSmoothing } = require('../utils'); // Using standard SMMA version

/**
 * Calculates the Average Directional Index (ADX), +DI, and -DI.
 *
 * Steps:
 * 1. Calculate True Range (TR), Positive Directional Movement (+DM), Negative Directional Movement (-DM).
 * 2. Smooth TR, +DM, -DM (typically using Wilder's smoothing method over a period, e.g., 14).
 * 3. Calculate Positive Directional Indicator (+DI) = (Smoothed +DM / Smoothed TR) * 100.
 * 4. Calculate Negative Directional Indicator (-DI) = (Smoothed -DM / Smoothed TR) * 100.
 * 5. Calculate Directional Index (DX) = |(+DI - -DI)| / |(+DI + -DI)| * 100.
 * 6. Calculate ADX = Smoothed DX (typically using Wilder's smoothing over the same period).
 *
 * @param {OHLCVData} data - Array of OHLCV data points.
 * @param {number} [period=14] - The period for smoothing and DI calculation.
 * @returns {IndicatorOutput} Array of ADX results. Each point contains a `values` object:
 *                            `{ adx: number, pdi: number, ndi: number }`.
 *                            - `adx`: Average Directional Index value.
 *                            - `pdi`: Positive Directional Indicator (+DI).
 *                            - `ndi`: Negative Directional Indicator (-DI).
 *                            Output starts when ADX can be calculated.
 *                            The first output point corresponds to original data index `data[2*period-1]`
 *                            (after enough data for initial TR/DM, first smoothing, and DX smoothing).
 */
function calculateADX(data, period = 14) {
    if (period <= 0 || !Number.isInteger(period)) {
        throw new Error('Period must be a positive integer.');
    }
    // Min length for one ADX value: 
    // TR/DM values needed: period-1 for first smoothing + period-1 for second smoothing = 2*period-2
    // Each TR/DM itself needs 2 data points, but they overlap.
    // To get `k` TR/DM values, we need `k+1` data points.
    // For the first ADX value, we need `period` DX values.
    // Each DX value comes from a smoothed TR/DM value.
    // The first smoothed TR/DM value requires `period` raw TR/DM values.
    // So, to get `period` DX values (for the first ADX smoothing), we need `period + (period-1)` raw TR/DM values.
    // This requires `period + (period-1) + 1` original data points.
    // = `2*period` original data points for the first ADX value.
    // The timestamp of this first ADX is data[2*period-1].
    // So data must have at least `2*period` elements.
    if (data.length < 2 * period) { 
        return [];
    }

    const trValues = [];
    const pdmValues = []; 
    const ndmValues = []; 

    for (let i = 1; i < data.length; i++) {
        const current = data[i];
        const previous = data[i - 1];
        const tr1 = current.high - current.low;
        const tr2 = Math.abs(current.high - previous.close);
        const tr3 = Math.abs(current.low - previous.close);
        trValues.push(Math.max(tr1, tr2, tr3));
        const upMove = current.high - previous.high;
        const downMove = previous.low - current.low;
        pdmValues.push(upMove > downMove && upMove > 0 ? upMove : 0);
        ndmValues.push(downMove > upMove && downMove > 0 ? downMove : 0);
    }

    if (trValues.length < period) return []; 

    const smoothedTR = wildersSmoothing(trValues, period);
    const smoothedPDM = wildersSmoothing(pdmValues, period);
    const smoothedNDM = wildersSmoothing(ndmValues, period);

    const pdiValues = []; 
    const ndiValues = []; 
    const dxValues = [];  

    for (let i = 0; i < smoothedTR.length; i++) {
        const str = smoothedTR[i];
        let pdi = 0, ndi = 0, dx = 0;
        if (str !== 0) {
            pdi = (smoothedPDM[i] / str) * 100;
            ndi = (smoothedNDM[i] / str) * 100;
            const sumDI = pdi + ndi;
            if (sumDI !== 0) {
                dx = (Math.abs(pdi - ndi) / sumDI) * 100;
            }
        }
        pdiValues.push(pdi);
        ndiValues.push(ndi);
        dxValues.push(dx);
    }

    if (dxValues.length < period) return []; 

    const adxLine = wildersSmoothing(dxValues, period);
    const adxOutput = [];

    // Align output
    // First adxLine value uses dxValues[0]...dxValues[period-1]. Timestamp is of dxValues[period-1].
    // dxValues[period-1] uses smoothedTR/PDM/NDM up to their index [period-1].
    // smoothedTR[period-1] uses trValues up to its index [period-1 + period-1] = [2*period-2].
    // trValues[2*period-2] comes from data[2*period-2 + 1] = data[2*period-1].
    // So, the first adxOutput point corresponds to data[2*period-1].
    // k here is index for adxLine.
    for (let k = 0; k < adxLine.length; k++) {
        // The k-th ADX value corresponds to the (k + period - 1)-th PDI/NDI value.
        const pdiNdiIndex = k + period - 1; 
        // The timestamp for this PDI/NDI value (and thus for this ADX value)
        // corresponds to the original data point at index:
        // (pdiNdiIndex for dxValues) + (period for initial TR values) = (k + period -1) + period = k + 2*period -1
        const outputDataIndex = k + (2 * period - 1);

        if (outputDataIndex < data.length) { // Ensure we don't go out of bounds for data's timestamp
             adxOutput.push({
                timestamp: data[outputDataIndex].timestamp,
                values: {
                    adx: adxLine[k],
                    pdi: pdiValues[pdiNdiIndex],
                    ndi: ndiValues[pdiNdiIndex],
                },
            });
        }
    }
    return adxOutput;
}

module.exports = { calculateADX }; // Removed wildersSmoothing export as it's now from utils

console.log("ADX function defined in financial-indicators/lib/indicators/adx.js");

/**
 * @typedef {import('../data_models').OHLCVData} OHLCVData
 * @typedef {import('../data_models').IndicatorPoint} IndicatorPoint
 * @typedef {import('../data_models').IndicatorOutput} IndicatorOutput
 */

/**
 * Calculates the Aroon Indicator (Aroon Up, Aroon Down, and Aroon Oscillator).
 * Aroon Up = ((Period - Periods Since Highest High) / Period) * 100
 * Aroon Down = ((Period - Periods Since Lowest Low) / Period) * 100
 * Aroon Oscillator = Aroon Up - Aroon Down
 *
 * @param {OHLCVData} data - Array of OHLCV data points. Requires 'high', 'low'.
 * @param {number} [period=25] - The lookback period.
 * @returns {IndicatorOutput} Array of Aroon values. Each point contains a `values` object:
 *          `{ up: number, down: number, oscillator: number }`.
 *          Output starts from data[period-1] because the calculation requires a full period window.
 *          Note: Some definitions start Aroon from data[period] because "periods since" for the first
 *          possible calculation (at data[period-1]) would refer to highs/lows within data[0]...data[period-1].
 *          If highest high is at data[period-1], periods since HH is 0.
 *          If highest high is at data[0], periods since HH is period-1.
 *          The calculation here aligns with common platforms where the first value appears after one full period.
 */
function calculateAroon(data, period = 25) {
  if (period <= 0 || !Number.isInteger(period)) {
    throw new Error('Period must be a positive integer.');
  }
  if (!data || data.length < period) {
    return []; // Not enough data for the lookback period
  }

  const aroonOutput = [];

  for (let i = period - 1; i < data.length; i++) {
    let highestHighInPeriod = -Infinity;
    let periodsSinceHH = 0;
    let lowestLowInPeriod = Infinity;
    let periodsSinceLL = 0;

    // Determine Highest High, Lowest Low, and periods since they occurred in the current window
    // The window is data[i - period + 1] through data[i]
    for (let j = 0; j < period; j++) {
      const currentPointInWindow = data[i - j]; // Iterating backwards through the window

      if (currentPointInWindow.high >= highestHighInPeriod) { // Use >= to get the most recent high if multiple same highs
        highestHighInPeriod = currentPointInWindow.high;
        periodsSinceHH = j; // j is periods ago from current `i`
      }
      if (currentPointInWindow.low <= lowestLowInPeriod) { // Use <= for most recent low
        lowestLowInPeriod = currentPointInWindow.low;
        periodsSinceLL = j;
      }
    }

    const aroonUp = ((period - periodsSinceHH) / period) * 100;
    const aroonDown = ((period - periodsSinceLL) / period) * 100;
    const aroonOscillator = aroonUp - aroonDown;

    aroonOutput.push({
      timestamp: data[i].timestamp,
      values: {
        up: aroonUp,
        down: aroonDown,
        oscillator: aroonOscillator,
      },
    });
  }

  return aroonOutput;
}

module.exports = { calculateAroon };

console.log("Aroon Indicator function defined in financial-indicators/lib/indicators/aroon.js");

/**
 * @typedef {import('../data_models').OHLCVData} OHLCVData
 * @typedef {import('../data_models').IndicatorPoint} IndicatorPoint
 * @typedef {import('../data_models').IndicatorOutput} IndicatorOutput
 */

const { wildersSmoothing } = require('../utils');

/**
 * Calculates the Average True Range (ATR).
 * 1. Calculate True Range (TR) for each period.
 *    TR = max(High - Low, |High - Previous Close|, |Low - Previous Close|)
 * 2. ATR = Wilder's smoothing of TR over a specified period.
 *
 * @param {OHLCVData} data - Array of OHLCV data points. Must have at least 2 points for first TR.
 * @param {number} [period=14] - The period for smoothing the True Range.
 * @returns {IndicatorOutput} Array of ATR values.
 *          Output starts when the first ATR value can be calculated, which is after `period` TR values
 *          have been computed. This means `period` days of TR values (requiring `period+1` original data points).
 *          So, the first ATR value corresponds to `data[period]`.
 */
function calculateATR(data, period = 14) {
  if (period <= 0 || !Number.isInteger(period)) {
    throw new Error('Period must be a positive integer.');
  }
  // Need at least 2 data points for the first TR value.
  // Need `period` TR values for the first ATR (SMA part of Wilder's).
  // So, need `period + 1` data points in total.
  if (data.length <= period) { 
    return [];
  }

  const trValuesWithTimestamp = []; // Store {timestamp, value: tr}

  // Calculate True Range values
  // First TR value uses data[0] and data[1], corresponds to data[1].timestamp
  for (let i = 1; i < data.length; i++) {
    const current = data[i];
    const previous = data[i - 1];

    const tr1 = current.high - current.low;
    const tr2 = Math.abs(current.high - previous.close);
    const tr3 = Math.abs(current.low - previous.close);
    trValuesWithTimestamp.push({
        timestamp: current.timestamp,
        value: Math.max(tr1, tr2, tr3)
    });
  }
  // trValuesWithTimestamp has (data.length - 1) elements.
  // Timestamps align with data[1] through data[data.length-1].

  if (trValuesWithTimestamp.length < period) {
    return []; // Not enough TR values for smoothing
  }

  const trNumericValues = trValuesWithTimestamp.map(tr => tr.value);
  const atrSmoothedValues = wildersSmoothing(trNumericValues, period);

  const atrOutput = [];
  // atrSmoothedValues has (trNumericValues.length - period + 1) elements.
  // The first element corresponds to the `period`-th element of `trNumericValues`.
  // trNumericValues[period-1] corresponds to trValuesWithTimestamp[period-1].
  // trValuesWithTimestamp[period-1] has timestamp data[period].timestamp.
  // So, the first ATR output corresponds to data[period].timestamp.

  for (let i = 0; i < atrSmoothedValues.length; i++) {
    // The i-th smoothed ATR value corresponds to the TR value at index (i + period - 1) in trValuesWithTimestamp
    const timestampIndexInTr = i + period - 1;
    atrOutput.push({
      timestamp: trValuesWithTimestamp[timestampIndexInTr].timestamp,
      value: atrSmoothedValues[i],
    });
  }

  return atrOutput;
}

module.exports = { calculateATR };

console.log("ATR function defined in financial-indicators/lib/indicators/atr.js");

/**
 * @typedef {import('../data_models').OHLCVData} OHLCVData
 * @typedef {import('../data_models').IndicatorPoint} IndicatorPoint
 * @typedef {import('../data_models').IndicatorOutput} IndicatorOutput
 */

const { calculateSMA } = require('./ma');

/**
 * Helper function to calculate Standard Deviation.
 * @param {number[]} values - Array of numbers.
 * @param {number} smaValue - The SMA of these values.
 * @returns {number} The standard deviation.
 */
function calculateStandardDeviation(values, smaValue) {
  if (values.length === 0) {
    return 0;
  }
  const squaredDifferencesSum = values.reduce((sum, value) => {
    return sum + Math.pow(value - smaValue, 2);
  }, 0);
  return Math.sqrt(squaredDifferencesSum / values.length);
}

/**
 * Calculates Bollinger Bands.
 * Middle Band: SMA(source, period)
 * Upper Band: Middle Band + (multiplier * StandardDeviation(source, period))
 * Lower Band: Middle Band - (multiplier * StandardDeviation(source, period))
 *
 * @param {OHLCVData} data - Array of OHLCV data points.
 * @param {number} [period=20] - The period for SMA and Standard Deviation.
 * @param {number} [multiplier=2] - The number of standard deviations for the upper/lower bands.
 * @param {string} [source='close'] - The source property from OHLCVData.
 * @returns {IndicatorOutput} Array of Bollinger Bands values. Each point contains a `values` object:
 *          `{ middle: number, upper: number, lower: number }`.
 *          Output starts from data[period-1].
 */
function calculateBollingerBands(data, period = 20, multiplier = 2, source = 'close') {
  if (period <= 0 || !Number.isInteger(period)) {
    throw new Error('Period must be a positive integer.');
  }
  if (multiplier < 0) {
    throw new Error('Multiplier cannot be negative.');
  }
  if (data.length < period) {
    return []; // Not enough data
  }

  const smaData = data.map(p => ({ timestamp: p.timestamp, close: p[source] }));
  const middleBandValues = calculateSMA(smaData, period, 'close'); // SMA output {timestamp, value}

  const bollingerBandsOutput = [];

  // MiddleBandValues start aligning with data[period-1]
  // For each middle band value, we need to calculate StdDev for the *same window*
  for (let i = 0; i < middleBandValues.length; i++) {
    const middleBandPoint = middleBandValues[i];
    const currentSmaValue = middleBandPoint.value;
    const currentTimestamp = middleBandPoint.timestamp;

    // The window for this SMA ended at an index in original data.
    // If middleBandValues[i] corresponds to original data[k],
    // then k = (period - 1) + i.
    const originalDataEndIndex = (period - 1) + i;

    const windowDataValues = [];
    for (let j = 0; j < period; j++) {
      windowDataValues.push(data[originalDataEndIndex - j][source]);
    }

    const stdDev = calculateStandardDeviation(windowDataValues, currentSmaValue);

    const upperBand = currentSmaValue + (multiplier * stdDev);
    const lowerBand = currentSmaValue - (multiplier * stdDev);

    bollingerBandsOutput.push({
      timestamp: currentTimestamp,
      values: {
        middle: currentSmaValue,
        upper: upperBand,
        lower: lowerBand,
      },
    });
  }

  return bollingerBandsOutput;
}

