    expect(result[3].values.up).toBeCloseTo(((3-1)/3)*100, 3);    // 66.667
    expect(result[3].values.down).toBeCloseTo(((3-2)/3)*100, 3);  // 33.333
    expect(result[3].values.oscillator).toBeCloseTo((2/3)*100 - (1/3)*100, 3); // 33.333
  });

